63	      const [profileRes, linksRes] = await Promise.all([
64	        supabase
65	          .from('creator_profiles')
66	          .select('*')
67	          .eq('user_id', user.id)
68	          .maybeSingle(),
69	        supabase
70	          .from('social_links')
71	          .select('*')
72	          .eq('user_id', user.id)
73	          .neq('status', 'unlinked'),
