75	      if (profileRes.error) throw profileRes.error;
76	      if (linksRes.error) throw linksRes.error;
77	      const linkRows = linksRes.data ?? [];
78	      const linkIds = linkRows.map((l) => l.id);
79	      const snapshotMap = new Map<
