1	// Relative-time formatter shared by the creator profile metrics row and
2	// future list surfaces (applications/submissions). Matches the "x ago"
3	// casing used throughout docs/design.md — plain-English, no i18n for v1.
4	//
5	// `now` is injectable so tests and the eventual metric-refresh realtime
6	// subscription can anchor the result without faking the system clock.
7	
8	export function formatRelativeTime(
9	  date: Date | null | undefined,
10	  now: Date = new Date(),
11	): string {
12	  if (!date) return 'Never';
13	  const diffMs = Math.max(0, now.getTime() - date.getTime());
14	  const minute = 60_000;
15	  const hour = 60 * minute;
16	  const day = 24 * hour;
17	  const month = 30 * day;
18	  const year = 365 * day;
19	
20	  if (diffMs < minute) return 'just now';
21	  if (diffMs < hour) return `${Math.floor(diffMs / minute)}m ago`;
22	  if (diffMs < day) return `${Math.floor(diffMs / hour)}h ago`;
23	  if (diffMs < month) return `${Math.floor(diffMs / day)}d ago`;
24	  if (diffMs < year) return `${Math.floor(diffMs / month)}mo ago`;
25	  return `${Math.floor(diffMs / year)}y ago`;
26	}
